// Build Overseer prompt — HONEST about what inputs this Phase 1 run has.
// Inputs available: 1h of agent_logs + active agent_tasks.
// Inputs NOT available: per-agent success rate / runtime (requires Analytics #10 = Phase 2).
// Therefore: we do NOT compute healthy/degraded/failed counts. We compute by_status as the proxy.

const tasks = $('Read active tasks').all().map(i => i.json).filter(t => t && t.id);
const logs  = $('Read recent logs').all().map(i => i.json).filter(l => l && l.id);

const by_status = { queued: 0, assigned: 0, in_progress: 0, blocked: 0 };
const blocked_by_reason = {};
let blocked_count = 0;

for (const t of tasks) {
  if (t && t.status in by_status) by_status[t.status]++;
  if (t && t.status === 'blocked') {
    blocked_count++;
    // metadata.blocked_on is the canonical location (migration 20260422_add_agent_tasks_metadata).
    // payload.blocked_on is a future-proof fallback — no pre-migration blocked rows exist today.
    const fromMeta = (t.metadata && typeof t.metadata === 'object') ? t.metadata.blocked_on : null;
    const fromPayload = (t.payload && typeof t.payload === 'object') ? t.payload.blocked_on : null;
    const reason = fromMeta ?? fromPayload ?? 'unspecified';
    blocked_by_reason[reason] = (blocked_by_reason[reason] || 0) + 1;
  }
}

let recent_errors = 0;
let recent_warnings = 0;
const active_agents = new Set();
const escalations = [];

for (const l of logs) {
  if (!l) continue;
  if (l.level === 'error' || l.level === 'fatal') recent_errors++;
  if (l.level === 'warn') recent_warnings++;
  if (l.agent_name) active_agents.add(l.agent_name);
  const tier = l.metadata && (l.metadata.tier ?? l.metadata.escalation_tier);
  if (tier === 'T4' || tier === 4) {
    escalations.push({
      agent: l.agent_name,
      message: (l.message || '').slice(0, 240),
      created_at: l.created_at,
    });
  }
}

// Severity classification (Phase 1 honest rules):
//   info  = no errors, no blocked tasks, no warnings
//   warn  = any blocked or any warning, no errors
//   error = any error/fatal log OR any T4 escalation
let level = 'info';
if (recent_warnings > 0 || blocked_count > 0) level = 'warn';
if (recent_errors > 0 || escalations.length > 0) level = 'error';

const snapshot = {
  task_count: tasks.length,
  by_status,
  blocked_count,
  blocked_by_reason,
  recent_errors,
  recent_warnings,
  active_agents: [...active_agents].sort(),
  escalations,
};

const system = [
  "You are Agent #00 Master Overseer for invest.com.au's 19-agent autonomous system (hourly monitor).",
  "",
  "IMPORTANT INPUT CONSTRAINTS — Phase 1 deployment. Be honest about what this run has:",
  "- You have the last 60 minutes of agent_logs and the full list of currently-active agent_tasks.",
  "- You DO NOT have per-agent success-rate or runtime metrics. Analytics #10 is not yet running (Phase 2).",
  "- DO NOT compute healthy_count/degraded_count/failed_count. Those are not derivable from this snapshot.",
  "- Use by_status, blocked_count, recent_errors, recent_warnings as the proxy signals.",
  "- DO NOT invent numbers the inputs don't support.",
  "",
  "Task this run:",
  "1) Summarise the system in <=200 words, severity-accurate per the provided 'level'.",
  "2) Flag any blocked task whose started_at/created_at is >6h ago (derive from the task rows).",
  "3) Suggest at most 3 follow-up actions — each one line, each addressed to a specific agent by number.",
  "",
  "Return a JSON block (```json ... ```) with keys: assessment (string), recommendations (array of strings), observed_level (string), echo {task_count, blocked_count, recent_errors, recent_warnings}. Follow the JSON block with your plain-English one-line digest.",
].join('\n');

const user = [
  `Run at: ${new Date().toISOString()}`,
  `Pre-computed level: ${level}`,
  ``,
  `Snapshot (ground truth, computed deterministically from inputs):`,
  '```json',
  JSON.stringify(snapshot, null, 2),
  '```',
  ``,
  `Recent error/warn/fatal logs (most recent first, up to 20):`,
  '```json',
  JSON.stringify(
    logs.filter(l => l && (l.level === 'error' || l.level === 'fatal' || l.level === 'warn')).slice(0, 20),
    null,
    2,
  ),
  '```',
].join('\n');

return [{ json: { system, user, level, snapshot } }];

// Parse Claude response.
// PARSE HARDENING: expected keys (task_count, blocked_count, recent_errors, recent_warnings)
// are explicitly set to null when missing from Claude's JSON — preserves null-vs-missing
// distinction for downstream monitors. Snapshot is also attached (ground truth) so Claude's
// (possibly null) echo never loses the source figures.

const resp    = $input.first().json;
const promptItem = $('Build Overseer prompt').first().json;
const snapshot   = promptItem.snapshot;
const level      = promptItem.level;

const contentBlocks = Array.isArray(resp && resp.content) ? resp.content : [];
const textBlock = contentBlocks.find(b => b && b.type === 'text');
const text = textBlock ? String(textBlock.text || '') : '';

let parsedMetadata = {};
const jsonMatch = text.match(/```json\s*([\s\S]*?)\s*```/);
if (jsonMatch) {
  try { parsedMetadata = JSON.parse(jsonMatch[1]) || {}; } catch (_) { parsedMetadata = {}; }
}
if (typeof parsedMetadata !== 'object' || parsedMetadata === null) parsedMetadata = {};

// Expected echo keys — explicit null, never undefined.
const expected = ['task_count', 'blocked_count', 'recent_errors', 'recent_warnings'];
const echo = (parsedMetadata && typeof parsedMetadata.echo === 'object' && parsedMetadata.echo !== null) ? parsedMetadata.echo : {};
for (const k of expected) {
  if (!(k in echo)) echo[k] = null;
}
parsedMetadata.echo = echo;

// Attach ground truth + run provenance.
parsedMetadata.snapshot = snapshot;
parsedMetadata.run_at   = new Date().toISOString();
parsedMetadata.model    = 'claude-opus-4-7';
parsedMetadata.anthropic_response_id = resp && resp.id ? resp.id : null;
parsedMetadata.stop_reason = resp && resp.stop_reason ? resp.stop_reason : null;
parsedMetadata.input_tokens  = resp && resp.usage ? resp.usage.input_tokens  ?? null : null;
parsedMetadata.output_tokens = resp && resp.usage ? resp.usage.output_tokens ?? null : null;

// Single-line digest for agent_logs.message (<=500 chars).
const firstLine = text.split(/\n+/).map(s => s.trim()).find(s => s && !s.startsWith('```')) || '';
const message = firstLine.slice(0, 500) || `Overseer hourly run (level=${level}, tasks=${snapshot.task_count})`;

return [{
  json: {
    agent_name: 'overseer',
    level,
    message,
    metadata: parsedMetadata,
  }
}];
